let canvas = document.createElement('canvas');
let ctx = canvas.getContext('2d');
document.body.appendChild(canvas);
canvas.width = 800;
canvas.height = 600;

let player = {
  x: 100,
  y: 100,
  speed: 200, // pixels per second
  width: 50,
  height: 50
};

let keys = {};

window.addEventListener('keydown', function(e) {
  keys[e.key] = true;
});

window.addEventListener('keyup', function(e) {
  keys[e.key] = false;
});

function update(deltaTime) {
  let distance = player.speed * (deltaTime / 1000);
  
  if (keys['ArrowUp']) player.y -= distance;
  if (keys['ArrowDown']) player.y += distance;
  if (keys['ArrowLeft']) player.x -= distance;
  if (keys['ArrowRight']) player.x += distance;
}

function draw() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = 'blue';
  ctx.fillRect(player.x, player.y, player.width, player.height);
}

let lastTime = performance.now();

function gameLoop() {
  let currentTime = performance.now();
  let deltaTime = Math.min(currentTime - lastTime, 100); // Cap deltaTime to prevent speed hack
  lastTime = currentTime;

  update(deltaTime);
  draw();

  requestAnimationFrame(gameLoop);
}

gameLoop();